import type { PaginationParams, PaginatedResponse, Merchant } from '~/types'

export function useMerchantsApi() {
    const { $api } = useNuxtApp()

    return {
        findAll(params?: PaginationParams & { status?: string; category?: string; rank?: string }) {
            return $api<PaginatedResponse<Merchant>>('/merchants', { params })
        },
        findById(id: string) {
            return $api<Merchant>(`/merchants/${id}`)
        },
        findByCode(code: string) {
            return $api<Merchant>(`/merchants/code/${code}`)
        },
        getStats() {
            return $api<any>('/merchants/stats')
        },
        update(id: string, data: Partial<Merchant>) {
            return $api<any>(`/merchants/${id}`, { method: 'PUT', body: data })
        },
        suspend(id: string, reason: string) {
            return $api<any>(`/merchants/${id}/suspend`, { method: 'PATCH', body: { reason } })
        },
        activate(id: string) {
            return $api<any>(`/merchants/${id}/activate`, { method: 'PATCH' })
        },
    }
}
